# --- Helper functions to load and save data ---

def load_jobs():
    jobs = []
    if not os.path.isfile(JOBS_FILE):
        return jobs
    try:
        with open(JOBS_FILE, 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 9:
                    continue
                job_id,title,company_id,location,salary_min,salary_max,category,description,posted_date = parts
                try:
                    jobs.append({
                        'job_id': int(job_id),
                        'title': title,
                        'company_id': int(company_id),
                        'location': location,
                        'salary_min': int(salary_min),
                        'salary_max': int(salary_max),
                        'category': category,
                        'description': description,
                        'posted_date': posted_date
                    })
                except ValueError:
                    continue
    except:
        pass
    return jobs


def load_companies():
    companies = []
    if not os.path.isfile(COMPANIES_FILE):
        return companies
    try:
        with open(COMPANIES_FILE, 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 6:
                    continue
                company_id,company_name,industry,location,employee_count,description = parts
                try:
                    companies.append({
                        'company_id': int(company_id),
                        'company_name': company_name,
                        'industry': industry,
                        'location': location,
                        'employee_count': int(employee_count),
                        'description': description
                    })
                except ValueError:
                    continue
    except:
        pass
    return companies


