from flask import Flask, render_template, redirect, url_for, request
import os
from datetime import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

# Helper functions to load data from files

DATA_DIR = 'data'

CURRENT_USER = 'john_diner'  # Simulated logged-in user for all routes

# Load users data into dict by username

def load_users():
    users = {}
    users_path = os.path.join(DATA_DIR, 'users.txt')
    if not os.path.exists(users_path):
        return users
    with open(users_path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) == 4:
                username, email, phone, full_name = parts
                users[username] = {
                    'username': username,
                    'email': email,
                    'phone': phone,
                    'full_name': full_name
                }
    return users

# Load menu items into list of dicts

def load_menu():
    menu = []
    menu_path = os.path.join(DATA_DIR, 'menu.txt')
    if not os.path.exists(menu_path):
        return menu
    with open(menu_path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) == 8:
                dish_id = int(parts[0])
                name = parts[1]
                category = parts[2]
                try:
                    price = float(parts[3])
                except ValueError:
                    price = 0.0
                description = parts[4]
                ingredients = parts[5]
                dietary = parts[6]
                try:
                    avg_rating = float(parts[7])
                except ValueError:
                    avg_rating = 0.0
                menu.append({
                    'dish_id': dish_id,
                    'name': name,
                    'category': category,
                    'price': price,
                    'description': description,
                    'ingredients': ingredients,
                    'dietary': dietary,
                    'avg_rating': avg_rating
                })
    return menu

# Load reservations into list of dicts

def load_reservations():
    reservations = []
    res_path = os.path.join(DATA_DIR, 'reservations.txt')
    if not os.path.exists(res_path):
        return reservations
    with open(res_path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) == 10:
                try:
                    reservation_id = int(parts[0])
                    party_size = int(parts[5])
                except ValueError:
                    continue
                reservations.append({
                    'reservation_id': reservation_id,
                    'username': parts[1],
                    'guest_name': parts[2],
                    'phone': parts[3],
                    'email': parts[4],
                    'party_size': party_size,
                    'date': parts[6],
                    'time': parts[7],
                    'special_requests': parts[8],
                    'status': parts[9]
                })
    return reservations

# Load waitlist data into list of dicts

def load_waitlist():
    waitlist = []
    waitlist_path = os.path.join(DATA_DIR, 'waitlist.txt')
    if not os.path.exists(waitlist_path):
        return waitlist
    with open(waitlist_path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) == 5:
                try:
                    waitlist_id = int(parts[0])
                    party_size = int(parts[2])
                except ValueError:
                    continue
                waitlist.append({
                    'waitlist_id': waitlist_id,
                    'username': parts[1],
                    'party_size': party_size,
                    'join_time': parts[3],
                    'status': parts[4]
                })
    return waitlist

# Load reviews data into list of dicts

def load_reviews():
    reviews = []
    reviews_path = os.path.join(DATA_DIR, 'reviews.txt')
    if not os.path.exists(reviews_path):
        return reviews
    with open(reviews_path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) == 6:
                try:
                    review_id = int(parts[0])
                    dish_id = int(parts[2])
                    rating = int(parts[3])
                except ValueError:
                    continue
                reviews.append({
                    'review_id': review_id,
                    'username': parts[1],
                    'dish_id': dish_id,
                    'rating': rating,
                    'review_text': parts[4],
                    'review_date': parts[5]
                })
    return reviews

# Save reservations to file

def save_reservations(reservations):
    res_path = os.path.join(DATA_DIR, 'reservations.txt')
    with open(res_path, 'w', encoding='utf-8') as f:
        for res in reservations:
            line = '|'.join([
                str(res['reservation_id']),
                res['username'],
                res['guest_name'],
                res['phone'],
                res['email'],
                str(res['party_size']),
                res['date'],
                res['time'],
                res['special_requests'],
                res['status']
            ]) + '\n'
            f.write(line)

# Save waitlist to file

def save_waitlist(waitlist):
    waitlist_path = os.path.join(DATA_DIR, 'waitlist.txt')
    with open(waitlist_path, 'w', encoding='utf-8') as f:
        for w in waitlist:
            line = '|'.join([
                str(w['waitlist_id']),
                w['username'],
                str(w['party_size']),
                w['join_time'],
                w['status']
            ]) + '\n'
            f.write(line)

# Save reviews to file

def save_reviews(reviews):
    reviews_path = os.path.join(DATA_DIR, 'reviews.txt')
    with open(reviews_path, 'w', encoding='utf-8') as f:
        for r in reviews:
            line = '|'.join([
                str(r['review_id']),
                r['username'],
                str(r['dish_id']),
                str(r['rating']),
                r['review_text'],
                r['review_date']
            ]) + '\n'
            f.write(line)

# Save users to file

def save_users(users):
    users_path = os.path.join(DATA_DIR, 'users.txt')
    with open(users_path, 'w', encoding='utf-8') as f:
        for u in users.values():
            line = '|'.join([
                u['username'],
                u['email'],
                u['phone'],
                u['full_name']
            ]) + '\n'
            f.write(line)

# Route implementations

@app.route('/')
def root():
    return redirect(url_for('dashboard'))

@app.route('/dashboard')
def dashboard():
    users = load_users()
    username = CURRENT_USER
    user_info = users.get(username)
    # Featured dishes: top 3 by avg_rating descending
    menu = load_menu()
    sorted_menu = sorted(menu, key=lambda x: x['avg_rating'], reverse=True)
    featured_dishes = []
    for d in sorted_menu[:3]:
        featured_dishes.append({
            'dish_id': d['dish_id'],
            'name': d['name'],
            'price': d['price']
        })

    # Upcoming reservations for current user (status "Upcoming"), sorted by date/time
    reservations = load_reservations()
    upcoming_reservations = [r for r in reservations if r['username']==username and r['status']=='Upcoming']
    def datetime_key(r):
        # Combine date and time for sorting
        try:
            return datetime.strptime(r['date'] + ' ' + r['time'], '%Y-%m-%d %H:%M')
        except ValueError:
            return datetime.max
    upcoming_reservations.sort(key=datetime_key)
    upcoming_reservations_list = []
    for r in upcoming_reservations:
        upcoming_reservations_list.append({
            'reservation_id': r['reservation_id'],
            'date': r['date'],
            'time': r['time'],
            'party_size': r['party_size'],
            'status': r['status']
        })

    return render_template('dashboard.html', username=username, featured_dishes=featured_dishes, upcoming_reservations=upcoming_reservations_list)

@app.route('/menu')
def menu():
    menu_items = load_menu()
    categories = sorted(set(d['category'] for d in menu_items))

    # Simplify menu_items for template keys as per spec
    simplified_menu_items = []
    for dish in menu_items:
        simplified_menu_items.append({
            'dish_id': dish['dish_id'],
            'name': dish['name'],
            'category': dish['category'],
            'price': dish['price'],
