@app.route('/make_reservation', methods=['GET', 'POST'])
def make_reservation():
    if request.method == 'POST':
        guest_name = request.form.get('guest_name', '').strip()
        party_size_str = request.form.get('party_size', '').strip()
        reservation_date = request.form.get('reservation_date', '').strip()

        # Validate party_size
        try:
            party_size = int(party_size_str)
            if party_size < 1 or party_size > 10:
                party_size = None
        except ValueError:
            party_size = None

        # Check required fields
        if not guest_name or not reservation_date or party_size is None:
            # Reload page on invalid input
            return render_template('make_reservation.html')

        # Load current user's contact info
        users = load_users()
        user = users.get(CURRENT_USER)
        if not user:
            return render_template('make_reservation.html')

        reservations = load_reservations()
        # Generate new reservation_id
        max_res_id = max([r['reservation_id'] for r in reservations], default=0)
        new_id = max_res_id + 1

        # Fixed time for all reservations? Spec does not say time input, keep at 19:00 by default
        reservation_time = "19:00"

        new_res = {
            'reservation_id': new_id,
            'username': CURRENT_USER,
            'guest_name': guest_name,
            'phone': user['phone'],
            'email': user['email'],
            'party_size': party_size,
            'date': reservation_date,
            'time': reservation_time,
            'special_requests': '',
            'status': 'Upcoming'
        }

        reservations.append(new_res)
        save_reservations(reservations)

        # After POST redirect to dashboard
        return redirect(url_for('dashboard'))

    # GET render form
    return render_template('make_reservation.html')

@app.route('/my_reservations', methods=['GET', 'POST'])
def my_reservations():
    username = CURRENT_USER
    reservations = load_reservations()
    user_reservations = [r for r in reservations if r['username'] == username]

    if request.method == 'POST':
        # Cancel reservation by id
        try:
            cancel_id = int(request.form.get('cancel_reservation_id', ''))
        except (ValueError, TypeError):
            cancel_id = None

        if cancel_id is not None:
            # Find and update status to 'Cancelled' for matching reservation
            changed = False
            for r in reservations:
                if r['reservation_id'] == cancel_id and r['username'] == username:
                    if r['status'] not in ['Cancelled', 'Completed']:
                        r['status'] = 'Cancelled'
                        changed = True
                    break
            if changed:
                save_reservations(reservations)

            # Reload user_reservations after change
            reservations = load_reservations()
            user_reservations = [r for r in reservations if r['username'] == username]

    # Sort user reservations by date/time descending
    def dt_sort(r):
        try:
            return datetime.strptime(r['date'] + ' ' + r['time'], '%Y-%m-%d %H:%M')
        except ValueError:
            return datetime.min

    user_reservations.sort(key=dt_sort, reverse=True)

    res_list = []
    for r in user_reservations:
        res_list.append({
            'reservation_id': r['reservation_id'],
            'date': r['date'],
            'time': r['time'],
            'party_size': r['party_size'],
            'status': r['status']
        })

    return render_template('my_reservations.html', reservations=res_list)

@app.route('/waitlist', methods=['GET', 'POST'])
def waitlist():
    username = CURRENT_USER
    waitlist = load_waitlist()

    # Find current user active waitlist entry
    user_waitlist = None
    for w in waitlist:
        if w['username'] == username and w['status'] == 'Active':
            user_waitlist = w
            break

    if request.method == 'POST':
        party_size_str = request.form.get('party_size', '').strip()
        try:
            party_size = int(party_size_str)
            if party_size < 1:
                party_size = None
        except ValueError:
            party_size = None

        if party_size is not None:
            # Add new waitlist entry if user does not have active one
            if user_waitlist is None:
                # Generate new waitlist_id
                max_wait_id = max([w['waitlist_id'] for w in waitlist], default=0)
                new_id = max_wait_id + 1

                join_time = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
                new_entry = {
                    'waitlist_id': new_id,
                    'username': username,
                    'party_size': party_size,
                    'join_time': join_time,
                    'status': 'Active'
                }
                waitlist.append(new_entry)
                save_waitlist(waitlist)
                user_waitlist = new_entry

    # Determine user position in waitlist
    user_position = None
    if user_waitlist is not None:
        # Only active entries
        active_waitlist = [w for w in waitlist if w['status'] == 'Active']
        # Sort by join_time ascending
        def parse_join_time(w):
            try:
                return datetime.strptime(w['join_time'], '%Y-%m-%d %H:%M:%S')
            except ValueError:
                return datetime.max
        active_waitlist.sort(key=parse_join_time)

        for idx, w in enumerate(active_waitlist, start=1):
            if w['waitlist_id'] == user_waitlist['waitlist_id']:
                user_position = idx
                break

    return render_template('waitlist.html', user_position=user_position)

@app.route('/my_reviews')
def my_reviews():
    username = CURRENT_USER
    reviews = load_reviews()
    menu = load_menu()

    # Filter reviews by current user
    user_reviews = [r for r in reviews if r['username'] == username]

    # Map dish_id to dish name for display
    dish_map = {d['dish_id']: d['name'] for d in menu}

    reviews_list = []
    for r in user_reviews:
        dish_name = dish_map.get(r['dish_id'], 'Unknown Dish')
        reviews_list.append({
            'review_id': r['review_id'],
            'dish_name': dish_name,
            'rating': r['rating'],
            'review_text': r['review_text']
        })

    return render_template('my_reviews.html', reviews=reviews_list)

@app.route('/write_review', methods=['GET', 'POST'])
def write_review():
    username = CURRENT_USER
    menu = load_menu()
    dishes = [{'dish_id': d['dish_id'], 'name': d['name']} for d in menu]

    if request.method == 'POST':
        dish_id_str = request.form.get('dish_id', '').strip()
        rating_str = request.form.get('rating', '').strip()
        review_text = request.form.get('review_text', '').strip()

        try:
            dish_id = int(dish_id_str)
            rating = int(rating_str)
            if rating < 1 or rating > 5:
                rating = None
        except ValueError:
            dish_id = None
            rating = None

        if dish_id is None or rating is None or not review_text:
            # Reload the form if invalid
            return render_template('write_review.html', dishes=dishes)

        reviews = load_reviews()
        max_review_id = max([r['review_id'] for r in reviews], default=0)
        new_id = max_review_id + 1

        today_str = datetime.now().strftime('%Y-%m-%d')

        new_review = {
            'review_id': new_id,
            'username': username,
            'dish_id': dish_id,
            'rating': rating,
            'review_text': review_text,
            'review_date': today_str
        }

        reviews.append(new_review)
        save_reviews(reviews)

        return redirect(url_for('my_reviews'))

    # GET
    return render_template('write_review.html', dishes=dishes)

@app.route('/profile', methods=['GET', 'POST'])
def profile():
    username = CURRENT_USER
    users = load_users()
    user_info = users.get(username, {'username': username, 'email': '', 'phone': '', 'full_name': ''})

    if request.method == 'POST':
        email = request.form.get('email', '').strip()
        if email:
            # Update user email
            user_info['email'] = email
            users[username] = user_info
            save_users(users)

    # Only expose username and email to template as per spec
    user_info_view = {'username': user_info.get('username', ''), 'email': user_info.get('email', '')}
    return render_template('profile.html', user_info=user_info_view)

if __name__ == '__main__':
    app.run(debug=True)

