# ----- Business Logic helpers -----

def generate_new_id(items_dict):
    if not items_dict:
        return 1
    return max(items_dict.keys()) + 1


def get_user(username):
    users = load_users()
    return users.get(username)


def get_courses_for_user(username):
    courses = load_courses()
    enrollments = load_enrollments()
    user_courses = []
    for e in enrollments.values():
        if e['username'] == username:
            course = courses.get(e['course_id'])
            if course:
                user_courses.append({
                    'course_id': course['course_id'],
                    'title': course['title'],
                    'progress': e['progress']
                })
    return user_courses


def get_enrollment(username, course_id):
    enrollments = load_enrollments()
    for e in enrollments.values():
        if e['username'] == username and e['course_id'] == course_id:
            return e
    return None


def get_lessons_for_course(course_id):
    # The design spec does not specify a file for lessons.
    # Since lessons are required for /learning/<course_id> route,
    # But design spec has no lessons.txt.
    # It's a gap. To address this, we will simulate some lessons by splitting description or dummy data.
    # We'll simulate 5 lessons per course labeled "Lesson 1 to Lesson 5" with placeholder content based on course title.

    courses = load_courses()
    course = courses.get(course_id)
    if not course:
        return []

    lessons = []
    for i in range(1, 6):
        lessons.append({
            'lesson_number': i,
            'title': f'Lesson {i}',
            'content': f'Content for Lesson {i} of course {course["title"]}.'
        })
    return lessons


def get_assignments_for_user(username):
    assignments = load_assignments()
    enrollments = load_enrollments()
    user_enrolled_courses = set(e['course_id'] for e in enrollments.values() if e['username'] == username)
    user_assignments = [a for a in assignments.values() if a['course_id'] in user_enrolled_courses]
    return user_assignments


def get_submission_for_assignment_user(assignment_id, username):
    submissions = load_submissions()
    for s in submissions.values():
        if s['assignment_id'] == assignment_id and s['username'] == username:
            return s
    return None


def has_certificate(username, course_id):
    certificates = load_certificates()
    for c in certificates.values():
        if c['username'] == username and c['course_id'] == course_id:
            return True
    return False


def create_certificate(username, course_id):
    certificates = load_certificates()
    # Check duplicate
    for c in certificates.values():
        if c['username'] == username and c['course_id'] == course_id:
            return
    certificate_id = generate_new_id(certificates)
    issue_date = datetime.now().strftime('%Y-%m-%d')
    certificates[certificate_id] = {
        'certificate_id': certificate_id,
        'username': username,
        'course_id': course_id,
        'issue_date': issue_date
    }
    save_certificates(certificates)


