@app.route('/learning/<int:course_id>', methods=['GET', 'POST'])
def course_learning(course_id):
    courses = load_courses()
    course = courses.get(course_id)
    if not course:
        return "Course not found", 404

    user = get_user(CURRENT_USER)
    if not user:
        return "User not found", 404

    enrollments = load_enrollments()
    enrollment = None
    for e in enrollments.values():
        if e['username'] == CURRENT_USER and e['course_id'] == course_id:
            enrollment = e
            break
    if not enrollment:
        return redirect(url_for('course_details', course_id=course_id))

    lessons = get_lessons_for_course(course_id)
    total_lessons = len(lessons)

    progress = enrollment['progress']  # 0-100 as int
    # completed_lessons = round((progress / 100) * total_lessons)
    completed_lessons = 0
    if total_lessons > 0:
        completed_lessons = int(progress * total_lessons / 100)
        if completed_lessons > total_lessons:
            completed_lessons = total_lessons

    current_lesson_number = completed_lessons + 1 if completed_lessons < total_lessons else total_lessons
    current_lesson = None
    if total_lessons == 0:
        current_lesson = None
    else:
        if current_lesson_number <= total_lessons:
            current_lesson = lessons[current_lesson_number - 1]
        else:
            current_lesson = lessons[-1]

    can_mark_complete = False
    if current_lesson is not None:
        # User can mark complete only if the current lesson is the next one to complete
        can_mark_complete = (completed_lessons < total_lessons)

    if request.method == 'POST':
        # Mark current lesson complete only if can_mark_complete
        if can_mark_complete:
            completed_lessons += 1
            new_progress = int((completed_lessons / total_lessons) * 100)
            enrollment['progress'] = new_progress
            if new_progress == 100:
                enrollment['status'] = 'Completed'
                # Generate certificate
                create_certificate(CURRENT_USER, course_id)
            else:
                enrollment['status'] = 'In Progress'

            enrollments[enrollment['enrollment_id']] = enrollment
            save_enrollments(enrollments)
            progress = new_progress
            # Update current lesson after progress
            if completed_lessons < total_lessons:
                current_lesson = lessons[completed_lessons]
            else:
                current_lesson = lessons[-1]

            can_mark_complete = (completed_lessons < total_lessons)

    return render_template('learning.html', course=course, lessons=lessons, current_lesson=current_lesson, progress=progress, can_mark_complete=can_mark_complete)


@app.route('/assignments')
def my_assignments():
    user = get_user(CURRENT_USER)
    if not user:
        return "User not found", 404

    assignments = get_assignments_for_user(CURRENT_USER)
    return render_template('assignments.html', assignments=assignments)


@app.route('/submit-assignment/<int:assignment_id>', methods=['GET', 'POST'])
def submit_assignment(assignment_id):
    assignments = load_assignments()
    assignment = assignments.get(assignment_id)
    if not assignment:
        return "Assignment not found", 404

    user = get_user(CURRENT_USER)
    if not user:
        return "User not found", 404

    submissions = load_submissions()
    submission = get_submission_for_assignment_user(assignment_id, CURRENT_USER)

    submission_status = None
    confirmation = None

    if request.method == 'POST':
        submission_text = request.form.get('submission_text', '').strip()
        if not submission_text:
            submission_status = 'Submission text cannot be empty.'
        else:
            if submission:
                # Update existing submission
                submission['submission_text'] = submission_text
                submission['submit_date'] = datetime.now().strftime('%Y-%m-%d')
                # Reset grade and feedback
                submission['grade'] = 0
                submission['feedback'] = ''
                submissions[submission['submission_id']] = submission
            else:
                # New submission
                submission_id = generate_new_id(submissions)
                new_sub = {
                    'submission_id': submission_id,
                    'assignment_id': assignment_id,
                    'username': CURRENT_USER,
                    'submission_text': submission_text,
                    'submit_date': datetime.now().strftime('%Y-%m-%d'),
                    'grade': 0,
                    'feedback': ''
                }
                submissions[submission_id] = new_sub
            save_submissions(submissions)
            submission_status = 'Submitted'
            confirmation = 'Your assignment has been submitted successfully.'

    # reload updated submission if any
    if not submission and submission_status == 'Submitted':
        submission = get_submission_for_assignment_user(assignment_id, CURRENT_USER)

    return render_template('submit_assignment.html', assignment=assignment, submission_status=submission_status, confirmation=confirmation)


@app.route('/certificates')
def certificates():
    user = get_user(CURRENT_USER)
    if not user:
        return "User not found", 404

    certificates = load_certificates()
    user_certificates = [c for c in certificates.values() if c['username'] == CURRENT_USER]
    return render_template('certificates.html', certificates=user_certificates)


@app.route('/profile', methods=['GET', 'POST'])
def user_profile():
    users = load_users()
    user = users.get(CURRENT_USER)
    if not user:
        return "User not found", 404

    update_status = None

    if request.method == 'POST':
        new_email = request.form.get('email', '').strip()
        new_fullname = request.form.get('fullname', '').strip()
        if not new_email or not new_fullname:
            update_status = 'Email and Full name cannot be empty.'
        else:
            user['email'] = new_email
            user['fullname'] = new_fullname
            users[CURRENT_USER] = user
            save_users(users)
            update_status = 'Profile updated successfully.'

    return render_template('profile.html', user_profile=user, update_status=update_status)


if __name__ == '__main__':
    app.run(debug=True, port=5000)

