@app.route('/learning/<int:course_id>', methods=['GET', 'POST'])
def course_learning(course_id):
    courses = load_courses()
    course = courses.get(course_id)
    if not course:
        return "Course not found", 404

    user = get_user(CURRENT_USER)
    if not user:
        return "User not found", 404

    enrollments = load_enrollments()
    enrollment = None
    for e in enrollments.values():
        if e['username'] == CURRENT_USER and e['course_id'] == course_id:
            enrollment = e
            break
    if not enrollment:
        return redirect(url_for('course_details', course_id=course_id))

    lessons = get_lessons_for_course(course_id)
    total_lessons = len(lessons)

    progress = enrollment['progress']  # 0-100 as int
    # completed_lessons = round((progress / 100) * total_lessons)
    completed_lessons = 0
    if total_lessons > 0:
        completed_lessons = int(progress * total_lessons / 100)
        if completed_lessons > total_lessons:
            completed_lessons = total_lessons

    current_lesson_number = completed_lessons + 1 if completed_lessons < total_lessons else total_lessons
    current_lesson = None
    if total_lessons == 0:
        current_lesson = None
    else:
        if current_lesson_number <= total_lessons:
            current_lesson = lessons[current_lesson_number - 1]
        else:
            current_lesson = lessons[-1]

    can_mark_complete = False
    if current_lesson is not None:
        # User can mark complete only if the current lesson is the next one to complete
        can_mark_complete = (completed_lessons < total_lessons)

    if request.method == 'POST':
        # Mark current lesson complete only if can_mark_complete
        if can_mark_complete:
            completed_lessons += 1
            new_progress = int((completed_lessons / total_lessons) * 100)
            enrollment['progress'] = new_progress
            if new_progress == 100:
                enrollment['status'] = 'Completed'
                # Generate certificate
                create_certificate(CURRENT_USER, course_id)
            else:
                enrollment['status'] = 'In Progress'

            enrollments[enrollment['enrollment_id']] = enrollment
            save_enrollments(enrollments)
            progress = new_progress
            # Update current lesson after progress
            if completed_lessons < total_lessons:
                current_lesson = lessons[completed_lessons]
            else:
                current_lesson = lessons[-1]

            can_mark_complete = (completed_lessons < total_lessons)

    return render_template('learning.html', course=course, lessons=lessons, current_lesson=current_lesson, progress=progress, can_mark_complete=can_mark_complete)


